      this.before = options.before
    } else {
      this.deep = this.user = this.lazy = this.sync = false
    }
    this.cb = cb
    this.id = ++uid // uid for batching
    this.active = true
    //!!!c dirty 是缓存计算值的开关 true时会计算 false时会读取缓存
    this.dirty = this.lazy // for lazy watchers  
    this.deps = []
    this.newDeps = []
    this.depIds = new Set()
    this.newDepIds = new Set()
    this.expression = process.env.NODE_ENV !== 'production'
      ? expOrFn.toString()
      : ''
    // parse expression for getter
    // 把 更新函数 或者 是计算属性的get 赋值给 watcher的 getter
    this.getter = expOrFn
    // computed的watcher 这里并不会计算值， render时的watcher会计算值
    this.value = this.lazy  
      ? undefined
      : this.get()
  }

  //  收集依赖
  get () {
    // 在这里把当前watcher 给了 Dep.target
    pushTarget(this)
    let value
    const vm = this.vm
    try {
      value = this.getter.call(vm, vm) //TODO： value可能是比较后的vnode
    } catch (e) {

    } finally {

      if (this.deep) {
        traverse(value)
      }
      popTarget()
      this.cleanupDeps()
    }
    return value
  }
	// dep 和 watcher 互相添加
  // watcher的 newDeps 添加dep， dep添加当前watcher
  addDep (dep: Dep) {
    const id = dep.id
    if (!this.newDepIds.has(id)) {
      this.newDepIds.add(id)
      this.newDeps.push(dep)
      if (!this.depIds.has(id)) {
        dep.addSub(this)
      }
    }
  }

  update () {
    // lazy sync 都是computed用的，在这里都是false
    // 所以会执行queueWatcher
    if (this.lazy) {
      this.dirty = true
    } else if (this.sync) {
      this.run()
    } else {
      queueWatcher(this)
    }
  }

  run () {
   // get函数会执行getter 然后执行 更新函数
   const value = this.get()

   // 调用computed的回调函数，此讨论不会执行   
   this.cb.call(this.vm, value, oldValue)
  }

   // watcher.deps存放的是data属性的dep。比如data：{a.b.c}  就会有a的dep  b的dep  c的dep
  depend () {
    let i = this.deps.length
    while (i--) {
      this.deps[i].depend()
    }
  }
}
