export function mountComponent (vm,el,hydrating) {
  vm.$el = el
  // 如果没有render 创建一个空节点
  if (!vm.$options.render) {
    vm.$options.render = createEmptyVNode
    }
  }
// 调用钩子
  callHook(vm, 'beforeMount')

  let updateComponent
// 生成updateComponent函数，可以直接关注 vm._update(vm._render(), hydrating)
// 这个函数会被传到组件的Watcher里面 当组件被通知更新时调用
// 他的作用很大，每次更新都会调用
  if (process.env.NODE_ENV !== 'production' && config.performance && mark) {
    updateComponent = () => {
      const name = vm._name
      const id = vm._uid
      const startTag = `vue-perf-start:${id}`
      const endTag = `vue-perf-end:${id}`

      mark(startTag)
      const vnode = vm._render()
      mark(endTag)
      measure(`vue ${name} render`, startTag, endTag)

      mark(startTag)
      vm._update(vnode, hydrating)
      mark(endTag)
      measure(`vue ${name} patch`, startTag, endTag)
    }
  } else {
    updateComponent = () => {
      vm._update(vm._render(), hydrating)
    }
  }

  // 生成watcher 实例
  new Watcher(vm, updateComponent, noop, {
    before () {
      if (vm._isMounted && !vm._isDestroyed) {
        callHook(vm, 'beforeUpdate')
      }
    }
  }, true /* isRenderWatcher */)


  hydrating = false

  // 调用钩子
  if (vm.$vnode == null) {
    vm._isMounted = true
    callHook(vm, 'mounted')
  }
  return vm
}
```
在上边过程中，组件在mount的时候会根据不同平台拓展option和render函数。然后再调用mount。调用mount实际上是执行mountComponent函数。这个函数会在组件作用域中new 一个Watcher 并把生成的updateComponent函数传入到watcher中，当每次更新时调用。<br />那么 watcher中发生什么，_render是什么，_update又是什么？<br />先看_render。在 core/instance/render.js
```javascript
 Vue.prototype._render = function (): VNode {
    const vm: Component = this
    const { render, _parentVnode } = vm.$options

// 如有父组件的Vnode，就处理父组件Vnode
    if (_parentVnode) {
      vm.$scopedSlots = normalizeScopedSlots(
        _parentVnode.data.scopedSlots,
        vm.$slots,
        vm.$scopedSlots
      )
    }

    // 设置$node 把parentNode赋值给他  也就是说当前组件的$vnode就是父组件
    vm.$vnode = _parentVnode

    let vnode
    try {

      currentRenderingInstance = vm
  // 主要代码： 调用vm上的 render 函数
  // 在这里执行render函数 生成 自己的vnode
      vnode = render.call(vm._renderProxy, vm.$createElement)
    } catch (e) {
      handleError(e, vm, `render`)
    } finally {
      currentRenderingInstance = null
    }
    // 如果vnode是数组
    if (Array.isArray(vnode) && vnode.length === 1) {
      vnode = vnode[0]
    }
    // 如果不是Vnode 返回空对象
    if (!(vnode instanceof VNode)) {
      vnode = createEmptyVNode()
    }
    // 设置父Vnode 返回自己的Vnode
    vnode.parent = _parentVnode
    return vnode
  }
