  el = el && query(el)  // 查找el
  const options = this.$options
  // 开始处理参数   
  // 这里要开始编译模板，如果有render函数就直接用他，
  // 没有就看有没有template,用template编译成render函数
  // 如果都没有，就看el，获取他的innerHTML
  if (!options.render) {  
