在上边过程中，组件在mount的时候会根据不同平台拓展option和render函数。然后再调用mount。调用mount实际上是执行mountComponent函数。这个函数会在组件作用域中new 一个Watcher 并把生成的updateComponent函数传入到watcher中，当每次更新时调用。<br />那么 watcher中发生什么，_render是什么，_update又是什么？<br />先看_render。在 core/instance/render.js
```javascript
 Vue.prototype._render = function (): VNode {
    const vm: Component = this
    const { render, _parentVnode } = vm.$options

// 如有父组件的Vnode，就处理父组件Vnode
    if (_parentVnode) {
      vm.$scopedSlots = normalizeScopedSlots(
        _parentVnode.data.scopedSlots,
        vm.$slots,
        vm.$scopedSlots
      )
    }

    // 设置$node 把parentNode赋值给他  也就是说当前组件的$vnode就是父组件
    vm.$vnode = _parentVnode

    let vnode
    try {

      currentRenderingInstance = vm
  // 主要代码： 调用vm上的 render 函数
  // 在这里执行render函数 生成 自己的vnode
      vnode = render.call(vm._renderProxy, vm.$createElement)
    } catch (e) {
      handleError(e, vm, `render`)
    } finally {
      currentRenderingInstance = null
    }
    // 如果vnode是数组
    if (Array.isArray(vnode) && vnode.length === 1) {
      vnode = vnode[0]
    }
    // 如果不是Vnode 返回空对象
    if (!(vnode instanceof VNode)) {
      vnode = createEmptyVNode()
    }
    // 设置父Vnode 返回自己的Vnode
    vnode.parent = _parentVnode
    return vnode
  }
